import { useState, useEffect } from "react";

/* ─────────────────────────────────────────
   VILLAGE DATA — all real information
───────────────────────────────────────── */
const VILLAGE = {
  nameHi: "खतेड़िया",
  nameEn: "Khatediya",
  tagline: "हमारी मिट्टी, हमारी पहचान — मध्यप्रदेश का गौरव",
  state: "Madhya Pradesh",
  stateHi: "मध्यप्रदेश",
  district: "Dewas",
  districtHi: "देवास",
  tehsil: "Dewas",
  division: "Ujjain",
  divisionHi: "उज्जैन",
  pincode: "455221",
  postOffice: "Karnawad",
  stdCode: "07272",
  elevation: "514 मीटर (समुद्र तल से ऊपर)",
  language: "मालवी, हिन्दी (देवनागरी)",
  assembly: "हाटपिपल्या विधानसभा क्षेत्र",
  parliament: "देवास लोकसभा क्षेत्र",
  highway: "NH-52",
  rivers: ["लोंद्री नदी", "पार्वती नदी"],
  mapLink: "https://maps.app.goo.gl/5FwP7uR9ZNmMasZHA",
};

const NAV = [
  { key: "home", label: "होम", icon: "🏠" },
  { key: "about", label: "परिचय", icon: "📋" },
  { key: "gallery", label: "गैलरी", icon: "🖼️" },
  { key: "map", label: "नक्शा", icon: "🗺️" },
];

/* ─────────────────────────────────────────
   MAIN COMPONENT
───────────────────────────────────────── */
export default function KhatediyaVillage() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [loaded, setLoaded] = useState(false);

  // Safe window access — only on client side
  const getPageFromHash = () => {
    if (typeof window === "undefined") return "home";
    const hash = window.location.hash.replace("#", "");
    const valid = ["home", "about", "gallery", "map"];
    return valid.includes(hash) ? hash : "home";
  };

  const [page, setPage] = useState("home");

  // Navigate: update state + push to browser history
  const navigate = (newPage) => {
    if (newPage === page) return;
    if (typeof window !== "undefined") {
      window.history.pushState({ page: newPage }, "", newPage === "home" ? "#home" : `#${newPage}`);
      window.scrollTo({ top: 0, behavior: "smooth" });
    }
    setPage(newPage);
    setMenuOpen(false);
  };

  // Set initial page from hash + handle back/forward — only on client
  useEffect(() => {
    // Set page from URL hash on first load
    setPage(getPageFromHash());

    // Set initial history entry
    const initialPage = getPageFromHash();
    window.history.replaceState(
      { page: initialPage },
      "",
      initialPage === "home" ? "#home" : `#${initialPage}`
    );

    // Handle browser back/forward buttons
    const handlePop = () => {
      setPage(getPageFromHash());
      window.scrollTo({ top: 0, behavior: "smooth" });
    };
    window.addEventListener("popstate", handlePop);
    return () => window.removeEventListener("popstate", handlePop);
  }, []);

  useEffect(() => {
    setLoaded(false);
    const t = setTimeout(() => setLoaded(true), 80);
    return () => clearTimeout(t);
  }, [page]);

  useEffect(() => {
    setTimeout(() => setLoaded(true), 80);
  }, []);

  return (
    <div style={s.root}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Tiro+Devanagari+Hindi:ital@0;1&family=Baloo+2:wght@400;600;700;800&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        ::-webkit-scrollbar { width: 6px; }
        ::-webkit-scrollbar-track { background: #1a0a00; }
        ::-webkit-scrollbar-thumb { background: #c47c2a; border-radius: 3px; }
        @keyframes fadeUp { from { opacity:0; transform:translateY(24px); } to { opacity:1; transform:translateY(0); } }
        @keyframes shimmer { 0%,100% { opacity:.6; } 50% { opacity:1; } }
        @keyframes float { 0%,100% { transform:translateY(0px); } 50% { transform:translateY(-8px); } }
        .anim { animation: fadeUp 0.55s ease both; }
        .anim1 { animation-delay:.05s; }
        .anim2 { animation-delay:.12s; }
        .anim3 { animation-delay:.2s; }
        .anim4 { animation-delay:.28s; }
        .anim5 { animation-delay:.36s; }
        .card-hover { transition: transform .2s, box-shadow .2s; }
        .card-hover:hover { transform: translateY(-4px); box-shadow: 0 12px 32px rgba(0,0,0,.18) !important; }
        .nav-btn { transition: all .18s; }
        .nav-btn:hover { background: rgba(255,200,80,.12) !important; }

        /* ── MOBILE RESPONSIVE ── */
        .desktop-nav { display: flex; }
        .hamburger-btn { display: none; }

        @media (max-width: 768px) {
          .desktop-nav { display: none !important; }
          .hamburger-btn { display: block !important; }

          .hero-title { font-size: 2.2rem !important; }
          .hero-section { padding: 48px 20px 60px !important; }
          .hero-tagline { font-size: 0.9rem !important; }

          .stats-grid { grid-template-columns: repeat(2, 1fr) !important; }
          .gallery-grid { grid-template-columns: repeat(2, 1fr) !important; }
          .nearby-grid { grid-template-columns: repeat(2, 1fr) !important; }
          .info-table-row { flex-direction: column !important; gap: 2px !important; }
          .info-val { text-align: left !important; }
          .about-intro { padding: 24px 18px !important; }
          .page-header { padding: 28px 0 20px !important; }
          .page-title { font-size: 1.6rem !important; }
          .hero-actions { flex-direction: column !important; align-items: center !important; }
          .hero-actions button { width: 100% !important; max-width: 280px !important; }
          .map-buttons { flex-direction: column !important; }
          .map-buttons a { text-align: center !important; }
          .lightbox-box { margin: 16px; }
          .filter-row { gap: 8px !important; }
          .footer-inner { padding: 28px 16px !important; }

          /* Map info — compact grid on mobile */
          .map-info { display: grid !important; grid-template-columns: 1fr 1fr !important; gap: 8px !important; margin-bottom: 16px !important; }
          .map-info-item { padding: 8px 10px !important; font-size: 0.78rem !important; flex: unset !important; min-height: unset !important; }
          .map-info-item span { font-size: 1rem !important; }

          /* Stat cards smaller */
          .stats-grid { gap: 8px !important; }
          .stat-card { padding: 14px 8px !important; }
          .stat-icon { font-size: 1.4rem !important; margin-bottom: 4px !important; }
          .stat-val { font-size: 0.82rem !important; }
          .stat-sub { font-size: 0.68rem !important; }

          /* Nearby smaller */
          .nearby-item { padding: 12px 10px !important; }
          .nearby-name { font-size: 0.95rem !important; }

          /* Gallery cards */
          .gallery-card-label { padding: 8px 10px !important; }

          /* Section padding */
          .map-card { padding: 16px !important; }
          .nearby-card { padding: 16px !important; }
          .table-card { padding: 16px !important; }
        }

        @media (max-width: 480px) {
          .hero-title { font-size: 1.8rem !important; }
          .stats-grid { grid-template-columns: repeat(2, 1fr) !important; }
          .gallery-grid { grid-template-columns: repeat(1, 1fr) !important; }
          .nearby-grid { grid-template-columns: repeat(1, 1fr) !important; }
          .map-info { grid-template-columns: 1fr !important; }
        }
      `}</style>

      {/* ── HEADER ── */}
      <header style={s.header}>
        <div style={s.headerInner}>
          <div style={s.brand}>
            <div style={s.brandIcon}>🏡</div>
            <div>
              <div style={s.brandHi}>{VILLAGE.nameHi}</div>
              <div style={s.brandEn}>{VILLAGE.nameEn} • {VILLAGE.districtHi}, {VILLAGE.stateHi}</div>
            </div>
          </div>
          {/* Desktop Nav */}
          <nav style={s.desktopNav} className="desktop-nav">
            {NAV.map(n => (
              <button key={n.key} className="nav-btn" onClick={() => navigate(n.key)} style={{
                ...s.navBtn,
                ...(page === n.key ? s.navBtnActive : {})
              }}>{n.icon} {n.label}</button>
            ))}
          </nav>
          {/* Mobile Hamburger */}
          <button onClick={() => setMenuOpen(!menuOpen)} style={s.hamburger} className="hamburger-btn">☰</button>
        </div>
        {menuOpen && (
          <div style={s.mobileMenu}>
            {NAV.map(n => (
              <button key={n.key} onClick={() => navigate(n.key)} style={{
                ...s.mobileNavBtn,
                ...(page === n.key ? { color: "#FFD700", fontWeight: "700" } : {})
              }}>{n.icon} {n.label}</button>
            ))}
          </div>
        )}
      </header>

      {/* ── MAIN ── */}
      <main style={s.main}>
        {loaded && (
          <>
            {page === "home" && <HomePage navigate={navigate} />}
            {page === "about" && <AboutPage />}
            {page === "gallery" && <GalleryPage />}
            {page === "map" && <MapPage />}
          </>
        )}
      </main>

      {/* ── FOOTER ── */}
      <footer style={s.footer}>
        <div style={s.footerContent} className="footer-inner">
          <div style={s.footerBrand}>🏡 {VILLAGE.nameHi} — {VILLAGE.nameEn}</div>
          <div style={s.footerMeta}>
            पिन: {VILLAGE.pincode} • STD: {VILLAGE.stdCode} • NH-52
          </div>

          {/* Instagram */}
          <a
            href="https://www.instagram.com/khatediya.wale"
            target="_blank"
            rel="noreferrer"
            style={s.instaBtn}
          >
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <rect x="2" y="2" width="20" height="20" rx="5" ry="5"/>
              <circle cx="12" cy="12" r="4.5"/>
              <circle cx="17.5" cy="6.5" r="1" fill="currentColor" stroke="none"/>
            </svg>
            @khatediya.wale
          </a>

          <div style={s.footerVerse}>जय हिन्द • जय मध्यप्रदेश • जय खतेड़िया</div>
          <div style={s.footerCopy}>© 2026 खतेड़िया ग्राम • सर्वाधिकार सुरक्षित</div>
        </div>
      </footer>
    </div>
  );
}

