/* ─────────────────────────────────────────
   GALLERY PAGE
───────────────────────────────────────── */

// ──────────────────────────────────────────
// 👇 अपनी गाँव की images यहाँ add करें
// हर item में:
//   src   → image का URL या base64
//   title → image का नाम (हिन्दी में)
//   cat   → category (मंदिर / खेत / त्योहार / तालाब / गाँव / अन्य)
// ──────────────────────────────────────────
const GALLERY = [
  { id: 1, src: "data:image/jpeg;base64,", title: "आँगनवाड़ी — खेल मैदान", cat: "गाँव", emoji: "🏫" },
  { id: 2, src: "data:image/jpeg;base64,", title: "ग्राम मंदिर", cat: "मंदिर", emoji: "⛩️" },
  { id: 3, src: "data:image/jpeg;base64,", title: "खतेड़िया — 1 KM मील का पत्थर", cat: "गाँव", emoji: "🛣️" },
  { id: 4, src: "data:image/jpeg;base64,", title: "मंदिर में राधा-कृष्ण", cat: "मंदिर", emoji: "🕉️" },
  { id: 5, src: "data:image/jpeg;base64,", title: "हनुमान जी की प्रतिमा", cat: "मंदिर", emoji: "🙏" },
  { id: 6, src: "data:image/jpeg;base64,", title: "पूजा — फूल और प्रसाद", cat: "त्योहार", emoji: "🌸" },
  { id: 7, src: "data:image/jpeg;base64,", title: "हरे मटर — ताज़ी फसल", cat: "खेत", emoji: "🫛" },
  { id: 8, src: "data:image/jpeg;base64,", title: "हरे-भरे खेत", cat: "खेत", emoji: "🌾" },
  { id: 9, src: "data:image/jpeg;base64,", title: "गेहूं की बाली", cat: "खेत", emoji: "🌿" },
];
function GalleryPage() {
  const [activeCat, setActiveCat] = useState("सभी");
  const [lightbox, setLightbox] = useState(null);

  const cats = ["सभी", ...new Set(GALLERY.map(g => g.cat))];
  const filtered = activeCat === "सभी" ? GALLERY : GALLERY.filter(g => g.cat === activeCat);

  return (
    <div>
      <div style={s.pageHeader} className="anim">
        <h2 style={s.pageTitle}>📸 गाँव की गैलरी</h2>
        <p style={s.pageSub}>खतेड़िया के सुंदर पल — हमारी यादें, हमारी पहचान</p>
      </div>

      {/* Category filter */}
      <div style={s.filterRow} className="anim anim2 filter-row">
        {cats.map(cat => (
          <button key={cat} onClick={() => setActiveCat(cat)} style={{
            ...s.filterBtn,
            ...(activeCat === cat ? s.filterBtnActive : {})
          }}>{cat}</button>
        ))}
      </div>

      {/* Gallery grid */}
      <div style={s.galleryGrid} className="anim anim3 gallery-grid">
        {filtered.map((item, i) => (
          <div
            key={item.id}
            className="card-hover"
            style={s.galleryCard}
            onClick={() => item.src && setLightbox(item)}
          >
            {item.src ? (
              <img src={item.src} alt={item.title} style={s.galleryImg} />
            ) : (
              <div style={s.galleryPlaceholder}>
                <div style={s.galleryEmoji}>{item.emoji}</div>
                <div style={s.galleryPlaceholderText}>फ़ोटो जल्द आएगी</div>
              </div>
            )}
            <div style={s.galleryLabel} className="gallery-card-label">
              <span style={s.galleryCat}>{item.cat}</span>
              <span style={s.galleryTitle}>{item.title}</span>
            </div>
          </div>
        ))}
      </div>

      {/* Lightbox */}
      {lightbox && (
        <div style={s.lightboxOverlay} onClick={() => setLightbox(null)}>
          <div style={s.lightboxBox} onClick={e => e.stopPropagation()}>
            <img src={lightbox.src} alt={lightbox.title} style={s.lightboxImg} />
            <div style={s.lightboxInfo}>
              <span style={s.galleryCat}>{lightbox.cat}</span>
              <span style={s.lightboxTitle}>{lightbox.title}</span>
            </div>
            <button onClick={() => setLightbox(null)} style={s.lightboxClose}>✕</button>
          </div>
        </div>
      )}
    </div>
  );
}

